/// All liquid glass parameters — matches the C++ ImGui controls exactly.
#[derive(Debug, Clone)]
pub struct UiState {
    // ── Shape ──
    pub power_factor: f32, // Superellipse power: 2=ellipse, 4=squircle, ∞=rect
    pub width: f32,        // Glass quad width (world units → pixels via scale)
    pub height: f32,       // Glass quad height

    // ── Distortion f(x) parameters ──
    pub a: f32, // f(x) = 1 - b * (c*e)^(-d*x-a)
    pub b: f32,
    pub c: f32,
    pub d: f32,
    pub f_power: f32, // Distortion power

    // ── Appearance ──
    pub noise: f32,       // Surface noise intensity
    pub glow_weight: f32, // Glow strength
    pub glow_edge0: f32,  // Glow smoothstep inner edge
    pub glow_edge1: f32,  // Glow smoothstep outer edge
    pub glow_bias: f32,   // Glow additive bias

    // ── Chromatic Aberration (Apple Liquid Glass effect) ──
    pub chromatic_aberration: f32, // Color separation strength
    pub aberration_samples: i32,   // Number of samples for quality

    // ── Blur ──
    pub blur_radius: f32,     // Blur kernel radius (pixels)
    pub blur_iterations: u32, // Multi-pass blur iteration count
    pub blur_downscale: f32,  // Blur downscale factor

    // ── Interaction ──
    pub mouse_control: bool,       // Glass follows mouse?
    pub position: [f32; 2],        // Glass center position (pixels)
    pub pixel_scale: f32,          // World-to-pixel scale factor
    pub camera_position: [f32; 2], // Camera position (world units)
    pub velocity: f32,             // Movement speed
    pub camera_velocity: f32,      // Camera movement speed

    // ── Background ──
    pub current_bg: usize,

    // ── Glass Material Variant ──
    pub glass_variant: usize, // Index into GLASS_VARIANTS
}

