impl Default for UiState {
    fn default() -> Self {
        Self {
            // Matches C++ defaults exactly
            power_factor: 3.0,
            width: 3.5,
            height: 3.5,

            a: 0.7,
            b: 2.3,
            c: 5.2,
            d: 6.9,
            f_power: 1.0,

            noise: 0.06,
            glow_weight: 0.25,
            glow_edge0: 0.5,
            glow_edge1: -0.5,
            glow_bias: 0.0,

            chromatic_aberration: 0.008, // Increased for more solid effect
            aberration_samples: 5,       // Higher quality for smoother edges

            blur_radius: 2.0,
            blur_iterations: 1,
            blur_downscale: 0.5,

            mouse_control: false,
            position: [400.0, 300.0],
            pixel_scale: 100.0, // 1 world unit = 100 pixels
            camera_position: [0.0, 0.0],
            velocity: 2.0,
            camera_velocity: 2.0,

            current_bg: 0,
            glass_variant: 0, // Regular
        }
    }
}

impl UiState {
    /// Glass width in pixels
    pub fn glass_width_px(&self) -> f32 {
        self.width * self.pixel_scale
    }

    /// Glass height in pixels
    pub fn glass_height_px(&self) -> f32 {
        self.height * self.pixel_scale
    }

    /// Apply preset size for current glass variant
    pub fn apply_variant_size(&mut self) {
        let (w, h) = GLASS_VARIANT_SIZES[self.glass_variant];
        self.width = w;
        self.height = h;
    }
}
